```aether:modules/notifications/module.contract.ts
import { defineContract } from 'aether';

export default defineContract({
  name: 'notifications',
  description: 'Manages user notifications, including listing and marking as read.',

  dependencies: {
    modules: ['auth'], // Depends on auth for user context
  },

  exposes: {
    routes: [
      { method: 'GET', path: '/notifications', auth: true },
    ],
    functions: ['listNotifications'],
    types: ['Notification', 'PaginatedNotifications'],
  },

  sideEffects: [
    'reads from: notifications table',
  ],

  invariants: [
    'Notifications are always associated with a user',
    'Unread notifications are prioritized in listings',
    'Pagination parameters must be positive integers',
  ],
});
```
```aether:modules/notifications/types.ts
import { User } from '@auth/types'; // Assuming User type is exposed by auth module

/**
 * Represents a single user notification.
 */
export interface Notification {
  id: string;
  user_id: User['id']; // Link to the User type from auth module
  title: string;
  body: string;
  is_read: boolean;
  created_at: Date;
  updated_at: Date;
  link?: string; // Optional link for the notification, e.g., to the related task
}

/**
 * Represents a paginated list of notifications.
 */
export interface PaginatedNotifications {
  data: Notification[];
  total: number;
  page: number;
  limit: number;
}
